import React, { useState, useEffect } from 'react';
import axios from 'axios';
import { useLanguage } from '../LanguageContext';
import { useModal } from '../ModalContext';
import './AdminPanel.css';

function AdminPanel({ userId }) {
  const { t } = useLanguage();
  const { showAlert, showConfirm } = useModal();
  const [activeTab, setActiveTab] = useState('users');
  const [users, setUsers] = useState([]);
  const [bookings, setBookings] = useState([]);
  const [editingUserId, setEditingUserId] = useState(null);
  const [editFormData, setEditFormData] = useState({});
  const [loading, setLoading] = useState(true);

  const fetchUsers = async () => {
    try {
      const response = await axios.get('/api/admin/usuarios', {
        headers: { 'x-admin-id': userId }
      });
      setUsers(response.data);
    } catch (error) {
      showAlert(t('actionFailed') + ': ' + (error.response?.data?.error || error.message));
    }
  };

  const fetchBookings = async () => {
    try {
      const response = await axios.get('/api/bookings');
      setBookings(response.data);
    } catch (error) {
      showAlert(t('actionFailed') + ': ' + (error.response?.data?.error || error.message));
    }
  };

  useEffect(() => {
    const loadData = async () => {
      setLoading(true);
      await Promise.all([fetchUsers(), fetchBookings()]);
      setLoading(false);
    };
    loadData();
  }, [userId]);

  const handleDeleteUser = (id) => {
    showConfirm(t('deleteConfirm'), async () => {
      try {
        await axios.delete(`/api/admin/usuarios/${id}`, {
          headers: { 'x-admin-id': userId }
        });
        showAlert(t('userDeleted'));
        setUsers(users.filter(u => u.id !== id));
      } catch (error) {
        showAlert(t('actionFailed') + ': ' + (error.response?.data?.error || error.message));
      }
    });
  };

  const handleDeleteBooking = (id) => {
    showConfirm(t('deleteBookingConfirm'), async () => {
      try {
        await axios.delete(`/api/bookings/${id}`);
        showAlert(t('bookingDeleted'));
        setBookings(bookings.filter(b => b.id !== id));
      } catch (error) {
        showAlert(t('actionFailed') + ': ' + (error.response?.data?.error || error.message));
      }
    });
  };

  const handleEditClick = (user) => {
    setEditingUserId(user.id);
    setEditFormData({
      nombre: user.nombre || '',
      apellido: user.apellido || '',
      mail: user.mail || '',
      enabled: user.enabled,
      is_admin: user.is_admin
    });
  };

  const handleCancelEdit = () => {
    setEditingUserId(null);
    setEditFormData({});
  };

  const handleFormChange = (e) => {
    const { name, value, type, checked } = e.target;
    setEditFormData({
      ...editFormData,
      [name]: type === 'checkbox' ? (checked ? 1 : 0) : value
    });
  };

  const handleSave = async (id) => {
    try {
      await axios.put(`/api/admin/usuarios/${id}`, editFormData, {
        headers: { 'x-admin-id': userId }
      });
      showAlert(t('userUpdated'));
      setEditingUserId(null);
      fetchUsers();
    } catch (error) {
      showAlert(t('actionFailed') + ': ' + (error.response?.data?.error || error.message));
    }
  };

  if (loading) {
    return <div className="admin-panel"><p>Loading...</p></div>;
  }

  return (
    <div className="admin-panel">
      <div className="admin-tabs">
        <button
          className={`tab-btn ${activeTab === 'users' ? 'active' : ''}`}
          onClick={() => setActiveTab('users')}
        >
          {t('tabUsers')}
        </button>
        <button
          className={`tab-btn ${activeTab === 'bookings' ? 'active' : ''}`}
          onClick={() => setActiveTab('bookings')}
        >
          {t('tabBookings')}
        </button>
      </div>

      {activeTab === 'users' && (
        <>
          <h2>{t('manageUsers')}</h2>
          <div className="table-container">
            <table className="admin-table">
              <thead>
                <tr>
                  <th>ID</th>
                  <th>{t('username')}</th>
                  <th>{t('name')}</th>
                  <th>{t('lastNameField')}</th>
                  <th>{t('emailField')}</th>
                  <th>{t('enabled')}</th>
                  <th>{t('role')}</th>
                  <th>{t('edit')}</th>
                </tr>
              </thead>
              <tbody>
                {users.map((u) => (
                  <tr key={u.id}>
                    <td>{u.id}</td>
                    <td>{u.usuario}</td>

                    {editingUserId === u.id ? (
                      <>
                        <td>
                          <input 
                            type="text" 
                            name="nombre" 
                            value={editFormData.nombre} 
                            onChange={handleFormChange} 
                          />
                        </td>
                        <td>
                          <input 
                            type="text" 
                            name="apellido" 
                            value={editFormData.apellido} 
                            onChange={handleFormChange} 
                          />
                        </td>
                        <td>
                          <input 
                            type="email" 
                            name="mail" 
                            value={editFormData.mail} 
                            onChange={handleFormChange} 
                          />
                        </td>
                        <td>
                          <input 
                            type="checkbox" 
                            name="enabled" 
                            checked={editFormData.enabled === 1} 
                            onChange={handleFormChange} 
                          />
                        </td>
                        <td>
                          <select name="is_admin" value={editFormData.is_admin} onChange={handleFormChange}>
                            <option value={0}>{t('userRole')}</option>
                            <option value={1}>{t('adminRole')}</option>
                          </select>
                        </td>
                        <td>
                          <button className="btn-save" onClick={() => handleSave(u.id)}>{t('save')}</button>
                          <button className="btn-cancel" onClick={handleCancelEdit}>{t('cancelEdit')}</button>
                        </td>
                      </>
                    ) : (
                      <>
                        <td>{u.nombre}</td>
                        <td>{u.apellido}</td>
                        <td>{u.mail}</td>
                        <td>{u.enabled ? t('yes') : t('no')}</td>
                        <td>{u.is_admin ? t('adminRole') : t('userRole')}</td>
                        <td>
                          <button className="btn-edit" onClick={() => handleEditClick(u)}>{t('edit')}</button>
                          <button className="btn-delete" onClick={() => handleDeleteUser(u.id)}>{t('delete')}</button>
                        </td>
                      </>
                    )}
                  </tr>
                ))}
              </tbody>
            </table>
          </div>
        </>
      )}

      {activeTab === 'bookings' && (
        <>
          <h2>{t('manageBookings')}</h2>
          <div className="table-container">
            {bookings.length > 0 ? (
              <table className="admin-table">
                <thead>
                  <tr>
                    <th>ID</th>
                    <th>{t('user')}</th>
                    <th>{t('hotel')}</th>
                    <th>{t('city')}</th>
                    <th>{t('checkIn')}</th>
                    <th>{t('checkOut')}</th>
                    <th>{t('pricePerNight')}</th>
                    <th>{t('totalPrice')}</th>
                    <th>{t('status')}</th>
                    <th>{t('edit')}</th>
                  </tr>
                </thead>
                <tbody>
                  {bookings.map((b) => (
                    <tr key={b.id}>
                      <td>{b.id}</td>
                      <td>{b.userName || `ID: ${b.userId}`}</td>
                      <td>{b.hotelName || `ID: ${b.hotelId}`}</td>
                      <td>{b.hotelCity || '-'}</td>
                      <td>{b.checkIn}</td>
                      <td>{b.checkOut}</td>
                      <td>${b.pricePerNight}</td>
                      <td><strong>${b.totalPrice}</strong></td>
                      <td><span className={`status-badge ${b.status}`}>{b.status}</span></td>
                      <td>
                        <button className="btn-delete" onClick={() => handleDeleteBooking(b.id)}>{t('delete')}</button>
                      </td>
                    </tr>
                  ))}
                </tbody>
              </table>
            ) : (
              <div className="no-results">{t('noBookingsFound')}</div>
            )}
          </div>
        </>
      )}
    </div>
  );
}

export default AdminPanel;
